<template>
    <div class="home">
        <div class='flod' @click="flod"/>
        <div class='home-head' v-show="isFlod">
            <el-button 
                v-for='(item, index) in $router.options.routes[1].children'
                :key='index'
                @click='goto(item)'>
                {{ item.name }}
            </el-button>
        </div>
        <div class='scroll-top' @click='goTop()'>顶</div>
        <div class='home-container max-height-width'>
            <router-view/>
        </div>
    </div>
</template>
<script>
    export default {
        data() {
            return {
                isFlod: false
            }
        },
        methods: {
            flod() {
                this.isFlod = !this.isFlod;
            },
            goto(data) {
                this.$router.push(`/${data.name}`)
            },
            goTop() {
                const dom = document.querySelector('html');
                let h = dom.scrollTop;
                const subH = parseInt(h/50);
                const timer = setInterval(function(){
                    h -= subH;
                    if(h <= 0){
                        dom.scrollTop = 0;
                        clearInterval(timer);
                    }else{
                        dom.scrollTop = h;
                    }
                },1)
            }
        }
    };
</script>